// NewEmbedder constructs the configured embedding backend.
// Called once at startup. Returns error if backend is unknown or unreachable.
func NewEmbedder(cfg config.EmbedderConfig) (Embedder, error) {
	switch cfg.Backend {
	case "ollama", "":
		return NewOllamaBackend(cfg)
	case "onnx":
		return nil, fmt.Errorf("ONNX Runtime backend not yet implemented")
	case "llamacpp":
		return nil, fmt.Errorf("llama.cpp backend not yet implemented")
	case "mock":
		return NewMockEmbedder(cfg.Dimensions), nil
	default:
		return nil, fmt.Errorf("unknown embedder backend: %q", cfg.Backend)
	}
}

